class Solution:
    def __init__(self):
        self.queue = []
        self.rear = 0
        self.front = 0

    def enqueue(self, nums):
        self.queue.append(nums)

    def dequeue(self):
        if self.rear > self.front:
            self.queue.pop(0)
            self.front += 1
        else:
            raise Exception('Queue is empty')

    def printQueue(self):
        print(' '.join(map(str, self.queue)))

s = Solution()
nums = input().split() 
for i in range(len(nums)):
    s.enqueue(nums[i])
    s.dequeue()

s.printQueue()

